/*
 * This is the primary high-level API for the project. In this folder there should be:
 * A class called InsightFacade, this should be in a file called InsightFacade.ts.
 * You should not change this interface at all or the test suite will not work.
 */

export enum InsightDatasetKind {
	Sections = "sections",
	Rooms = "rooms",
}

export interface InsightDataset {
	id: string;
	kind: InsightDatasetKind;
	numRows: number;
}

export type InsightResult = Record<string, string | number>;

export class InsightError extends Error {
	constructor(message?: string) {
		super(message);
		Error.captureStackTrace(this, InsightError);
	}
}

export class NotFoundError extends Error {
	constructor(message?: string) {
		super(message);
		Error.captureStackTrace(this, NotFoundError);
	}
}

export class ResultTooLargeError extends Error {
	constructor(message?: string) {
		super(message);
		Error.captureStackTrace(this, ResultTooLargeError);
	}
}

export interface IInsightFacade {
	/**
	 * Add a dataset to insightUBC.
	 *
	 * @param id  The id of the dataset being added. Follows the format /^[^_]+$/
	 * @param content  The base64 content of the dataset. This content should be in the form of a serialized zip file.
	 * @param kind  The kind of the dataset
	 *
	 * @return Promise <string[]>
	 *
	 * The promise should fulfill on a successful add, reject for any failures.
	 * The promise should fulfill with a string array,
	 * containing the ids of all currently added datasets upon a successful add.
	 * The promise should reject with an InsightError describing the error.
	 *
	 * An id is invalid if it contains an underscore, or is only whitespace characters.
	 * If id is the same as the id of an already added dataset, the dataset should be rejected and not saved.
	 *
	 * After receiving the dataset, it should be processed into a data structure of
	 * your design. The processed data structure should be persisted to disk; your
	 * system should be able to load this persisted value into memory for answering
	 * queries.
	 *
	 * Ultimately, a dataset must be added or loaded from disk before queries can
	 * be successfully answered.
	 */
	addDataset(id: string, content: string, kind: InsightDatasetKind): Promise<string[]>;

	/**
	 * Remove a dataset from insightUBC.
	 *
	 * @param id  The id of the dataset to remove. Follows the format /^[^_]+$/
	 *
	 * @return Promise <string>
	 *
	 * The promise should fulfill upon a successful removal, reject on any error.
	 * Attempting to remove a dataset that hasn't been added yet counts as an error.
	 *
	 * An id is invalid if it contains an underscore, or is only whitespace characters.
	 *
	 * The promise should fulfill the id of the dataset that was removed.
	 * The promise should reject with a NotFoundError (if a valid id was not yet added)
	 * or an InsightError (invalid id or any other source of failure) describing the error.
	 *
	 * This will delete both disk and memory caches for the dataset for the id meaning
	 * that subsequent queries for that id should fail unless a new addDataset happens first.
	 */
	removeDataset(id: string): Promise<string>;

	/**
	 * Perform a query on insightUBC.
	 *
	 * @param query  The query to be performed.
	 *
	 * If a query is incorrectly formatted, references a dataset not added (in memory or on disk),
	 * or references multiple datasets, it should be rejected.
	 *
	 * @return Promise <InsightResult[]>
	 *
	 * The promise should fulfill with an array of results.
	 * The promise should reject with a ResultTooLargeError (if the query returns too many results)
	 * or an InsightError (for any other source of failure) describing the error.
	 */
	performQuery(query: unknown): Promise<InsightResult[]>;

	/**
	 * List all currently added datasets, their types, and number of rows.
	 *
	 * @return Promise <InsightDataset[]>
	 * The promise should fulfill an array of currently added InsightDatasets, and will only fulfill.
	 */
	listDatasets(): Promise<InsightDataset[]>;
}

import {
	IInsightFacade,
	InsightDataset,
	InsightDatasetKind,
	InsightResult,
	NotFoundError,
	InsightError,
	ResultTooLargeError,
} from "./IInsightFacade";
import JSZip, { loadAsync } from "jszip";
import * as fs from "fs-extra";
import { Datasets, Section } from "./helperClass";
import { HelperFunction } from "./helperFunction";
// import * as path from "path";

export default class InsightFacade implements IInsightFacade {
	private datasets = new Map<string, Datasets>();
	private hf = new HelperFunction();

	public async addDataset(id: string, content: string, kind: InsightDatasetKind): Promise<string[]> {
		await this.loadDatasetsFromDisk(kind);

		if (!this.hf.isValidId(id)) {
			throw new InsightError("Invalid id");
		}

		if (this.datasets.has(id)) {
			throw new InsightError("Dataset already exists");
		}

		let zipData: JSZip;
		try {
			zipData = await loadAsync(content, { base64: true });
			const files = zipData.folder("courses");
			if (!files) {
				throw new InsightError("no courses folder");
			}
			if (files.length === 0) {
				throw new InsightError("no content in files");
			}
			await this.parseZipFile(id, zipData, this.datasets);
		} catch (_err) {
			throw new InsightError("Fail to unzip");
		}

		return Array.from(this.datasets.keys());
	}

	public async removeDataset(id: string): Promise<string> {
		await this.loadDatasetsFromDisk(InsightDatasetKind.Sections);
		await this.loadDatasetsFromDisk(InsightDatasetKind.Rooms);

		if (!this.hf.isValidId(id)) {
			throw new InsightError("Invalid id");
		}

		if (!this.datasets.has(id)) {
			throw new NotFoundError("cannot find id");
		}

		this.datasets.delete(id);

		await this.saveDatasetsDisk(this.datasets);

		return id;
	}

	public async listDatasets(): Promise<InsightDataset[]> {
		await this.loadDatasetsFromDisk(InsightDatasetKind.Sections);
		await this.loadDatasetsFromDisk(InsightDatasetKind.Rooms);

		const insightDatasetList: InsightDataset[] = [];
		const datasetList = this.datasets.entries();

		for (const [id, dataset] of datasetList) {
			// from chatGPT (next 5 lines)
			const insightDataset: InsightDataset = {
				id: id,
				kind: dataset.kind,
				numRows: dataset.numRows,
			};
			insightDatasetList.push(insightDataset);
		}
		return insightDatasetList;
	}

	public async performQuery(query: unknown): Promise<InsightResult[]> {
		// load from disk
		await this.loadDatasetsFromDisk(InsightDatasetKind.Sections);
		await this.loadDatasetsFromDisk(InsightDatasetKind.Rooms);

		// go through the query (from chatGPT)
		const { WHERE, OPTIONS } = query as any;

		// check valid WHERE and valid OPTION
		if (!WHERE || !OPTIONS) {
			throw new InsightError("invalid format");
		}

		if (typeof query !== "object") {
			throw new InsightError();
		}

		if (!query) {
			throw new InsightError();
		}

		for (const x of Object.keys(query)) {
			if (x !== "WHERE" && x !== "OPTIONS") {
				throw new InsightError();
			}
		}

		// get id from first element of column
		const queryId = await this.hf.getQueryId(OPTIONS);

		const foundDataset = this.datasets.get(queryId);

		// no dataset with id found
		if (!foundDataset) {
			throw new InsightError("reference not found");
		}

		const filtered = await this.handleWhere(WHERE, foundDataset.sections, queryId);

		if (filtered.length === 0) {
			return [];
		}

		// handle OPTIONS
		const result = await this.handleOptions(OPTIONS, filtered, queryId);

		const limit = 5000;

		if (result.length > limit) {
			throw new ResultTooLargeError("result too large");
		}

		// console.log(result);

		return result;
	}

	private async handleOptions(options: any, filtered: Section[], queryId: string): Promise<InsightResult[]> {
		const columns = options.COLUMNS;
		const order = options.ORDER;
		const columnParam: String[] = [];

		// map filtered sections to the required columns
		const results: InsightResult[] = filtered.map((section) => {
			const result: any = {};
			columns.forEach((col: string) => {
				const [datasetId, field] = col.split("_");
				if (datasetId !== queryId) {
					throw new InsightError("invalid dataset");
				}
				columnParam.push(field);
				result[col] = this.hf.getParamAll(field, section);
			});
			return result;
		});

		// If ORDER exists, sort the results
		if (order) {
			this.sortResults(results, order, queryId, columnParam);
		}

		return results;
	}

	private sortResults(results: InsightResult[], order: string, queryId: string, columnParam: String[]): void {
		if (typeof order !== "string") {
			throw new InsightError("Invalid order key");
		}

		const [dataset, orderParam] = order.split("_");
		if (dataset !== queryId) {
			throw new InsightError("Invalid dataset");
		}
		if (!columnParam.includes(orderParam)) {
			throw new InsightError("");
		}

		results.sort((a, b) => {
			const aValue = a[order];
			const bValue = b[order];

			if (typeof aValue === "string" && typeof bValue === "string") {
				return aValue.localeCompare(bValue); // Lexical comparison for strings
			} else if (typeof aValue === "number" && typeof bValue === "number") {
				return aValue - bValue; // Numeric comparison for numbers
			} else {
				throw new InsightError("Cannot compare values of different types");
			}
		});
	}

	private async handleWhere(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		// base case
		if (Object.keys(where).length === 0) {
			return sections;
		}
		if (where.AND || where.OR) {
			// handle logic comp
			return await this.handleLogicComp(where, sections, queryId);
		}
		if (where.NOT) {
			return await this.handleNegation(where, sections, queryId);
		}
		if (where.IS) {
			return await this.handleSComp(where, sections, queryId);
		}
		if (where.LT || where.GT || where.EQ) {
			return await this.handleMComp(where, sections, queryId);
		}

		throw new InsightError("invalid ebnf");
	}

	private async handleMComp(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		// now we have list of sections with ID that we want
		if (where.GT) {
			return await this.hf.handleGreaterThan(where, sections, queryId);
		}
		if (where.LT) {
			return await this.hf.handleLessThan(where, sections, queryId);
		}

		if (where.EQ) {
			return await this.hf.handleEqual(where, sections, queryId);
		}
		throw new InsightError("no m comp");
	}

	private async handleSComp(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		if (Object.keys(where.IS).length === 0) {
			throw new InsightError("Invalid Query Syntax for IS");
		}

		const [key, value]: [string, unknown] = Object.entries(where.IS)[0];
		const param = key.split("_")[1];
		const dataset = key.split("_")[0];
		if (dataset !== queryId) {
			throw new InsightError("");
		}

		if (typeof value !== "string") {
			throw new InsightError("invalid skey");
		}
		const a = sections.filter((s) => {
			const valueType = this.hf.getValueType(value);
			const compareValue = this.hf.getParamString(param, s);
			if (valueType === "startend") {
				const newString = value.slice(1, -1);
				return compareValue.includes(newString);
			} else if (valueType === "start") {
				const newString = value.slice(1);
				// console.log(newString);
				return compareValue.endsWith(newString);
			} else if (valueType === "end") {
				const newString = value.slice(0, -1);
				return compareValue.startsWith(newString);
			} else {
				return compareValue === value;
			}
		});

		return a;
	}

	private async handleLogicComp(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		// where.LOGIC is an array, e.g. ( { AND: [ { GT: [Object] }, { IS: [Object] } ] } )
		// therefore filteredSections in handleOr and handleAnd stores the result of each recursion of each branches inside the where.LOGIC

		if (where.OR) {
			return this.handleOr(where, sections, queryId);
		}

		if (where.AND) {
			return this.handleAnd(where, sections, queryId);
		}

		throw new InsightError(`Invalid logical operator: ${where[0]}`);
	}

	private async handleOr(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		if (where.OR.length === 0) {
			throw new InsightError("Invalid Query Syntax");
		}

		const orPromises = where.OR.map(async (condition: any) => this.handleWhere(condition, sections, queryId));

		const filteredSections = await Promise.all(orPromises);

		// check whether the section is found in one of the filteredSections members
		function sectionChecker(s: Section): boolean {
			for (const x of filteredSections) {
				if (x.includes(s)) {
					return true;
				}
			}
			return false;
		}

		return sections.filter((s: Section) => {
			return sectionChecker(s);
		});
	}

	private async handleAnd(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		if (where.AND.length === 0) {
			throw new InsightError("Invalid Query Syntax");
		}

		const andPromises = where.AND.map(async (condition: any) => this.handleWhere(condition, sections, queryId));

		const filteredSections = await Promise.all(andPromises);

		return sections.filter((section) => filteredSections.every((filtered) => filtered.includes(section)));
	}

	private async handleNegation(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		const filteredSections = await this.handleWhere(where.NOT, sections, queryId);
		return sections.filter((s: Section) => {
			return !filteredSections.includes(s);
		});
	}

	private async loadDatasetsFromDisk(k: InsightDatasetKind): Promise<void> {
		if (k === InsightDatasetKind.Sections) {
			const exist = await fs.pathExists("./data/Datasets.json");

			if (!exist) {
				return;
			}

			const datasetArray: [string, Datasets][] = await fs.readJSON("./data/Datasets.json");

			for (const [id, dataset] of datasetArray) {
				if (this.datasets.has(id)) {
					continue;
				}
				const newData = new Datasets(k);
				newData.sections = dataset.sections;
				newData.numRows = dataset.numRows;
				newData.kind = dataset.kind;
				this.datasets.set(id, newData);
			}
		}
	}

	private async parseZipFile(id: string, zip: JSZip, datasets: Map<string, Datasets>): Promise<void> {
		const dumpDatasets = new Datasets(InsightDatasetKind.Sections);
		const zipContent = zip.files;
		const keyContent = Object.keys(zipContent);
		const filteredContent = keyContent.filter((checkPath: string) => {
			return checkPath.startsWith("courses/") && checkPath !== "courses/";
		});

		const listPromises = filteredContent.map(async (checkPath) => {
			const file = zip.file(checkPath);
			if (file) {
				const stringContent = await file.async("string");
				return JSON.parse(stringContent).result;
			}
		});

		const fulfillPromises = await Promise.all(listPromises);

		for (const course of fulfillPromises) {
			for (const section of course) {
				const dumpSection = new Section(section);
				dumpDatasets.addSection(dumpSection);
			}
		}
		if (dumpDatasets.sections.length === 0) {
			throw new InsightError("");
		}

		// set map
		datasets.set(id, dumpDatasets);

		await this.saveDatasetsDisk(datasets);
	}

	private async saveDatasetsDisk(datasets: Map<String, Datasets>): Promise<void> {
		// Convert Map to an object before writing, from chatGPT
		const datasetsArray = Array.from(datasets.entries());

		await fs.ensureDir("./data");

		await fs.writeJSON("./data/Datasets.json", datasetsArray);
	}
}

import { InsightDatasetKind, InsightError } from "./IInsightFacade";

export class Datasets {
	public sections: Section[];
	public numRows: number;
	public kind: InsightDatasetKind;

	constructor(k: InsightDatasetKind) {
		this.sections = [];
		this.numRows = 0;
		this.kind = k;
	}

	public addSection(newCourse: Section): void {
		++this.numRows;
		this.sections.push(newCourse);
	}
}

export class Section {
	public uuid: string;
	public id: string;
	public title: string;
	public instructor: string;
	public dept: string;
	public year: number;
	public avg: number;
	public pass: number;
	public fail: number;
	public audit: number;

	constructor(section: any) {
		// check if section is valid
		if (!this.isValidSection(section)) {
			throw new InsightError("Undefined variable -> invalid section");
		}
		try {
			this.uuid = String(section.id);
			this.id = String(section.Course);
			this.title = String(section.Title);
			this.instructor = String(section.Professor);
			this.dept = String(section.Subject);
			if (section.Section === "overall") {
				this.year = 1900;
			} else {
				this.year = this.anyToNum(section.Year);
			}
			this.avg = this.anyToNum(section.Avg);
			this.pass = this.anyToNum(section.Pass);
			this.fail = this.anyToNum(section.Fail);
			this.audit = this.anyToNum(section.Audit);
		} catch (_err) {
			throw new InsightError("invalid variable type");
		}
	}

	public isValidSection(c: any): boolean {
		return (
			c.id !== undefined ||
			c.Course !== undefined ||
			c.title !== undefined ||
			c.Professor !== undefined ||
			c.Subject !== undefined ||
			c.Section !== undefined ||
			c.Year !== undefined ||
			c.Avg !== undefined ||
			c.Pass !== undefined ||
			c.Fail !== undefined ||
			c.Audit !== undefined
		);
	}

	public anyToNum(n: any): number {
		const num = Number(n);
		if (isNaN(num)) {
			throw new InsightError("n is not a number");
		}
		return num;
	}
}

export class Room {
	public fullname: string;
	public shortname: string;
	public number: string;
	public name: string;
	public address: string;
	public lat: number;
	public lon: number;
	public seats: number;
	public type: string;
	public furniture: string;
	public href: string;

	constructor(room: any) {
		// check if section is valid
		if (!this.isValidRoom(room)) {
			throw new InsightError("Undefined variable -> invalid section");
		}
		try {
			this.fullname = String(room.id);
			this.shortname = String(room.shortname);
			this.number = String(room.number);
			this.name = String(room.name);
			this.address = String(room.address);
			this.lat = this.anyToNum(room.lat);
			this.lon = this.anyToNum(room.lon);
			this.seats = this.anyToNum(room.seats);
			this.type = String(room.type);
			this.furniture = String(room.furniture);
			this.href = String(room.href);
		} catch (_err) {
			throw new InsightError("invalid variable type");
		}
	}

	public isValidRoom(r: any): boolean {
		return typeof r === "string";
	}

	public anyToNum(n: any): number {
		const num = Number(n);
		if (isNaN(num)) {
			throw new InsightError("n is not a number");
		}
		return num;
	}
}

import { InsightError } from "./IInsightFacade";
import { Section } from "./helperClass";

export class HelperFunction {
	public getParamNum(param: String, s: Section): number {
		if (param === "year") {
			return s.year;
		}
		if (param === "avg") {
			return s.avg;
		}
		if (param === "pass") {
			return s.pass;
		}
		if (param === "fail") {
			return s.fail;
		}
		if (param === "audit") {
			return s.audit;
		}
		throw new InsightError();
	}

	public getParamString(param: String, s: Section): string {
		if (param === "uuid") {
			return s.uuid;
		}
		if (param === "id") {
			return s.id;
		}
		if (param === "title") {
			return s.title;
		}
		if (param === "instructor") {
			return s.instructor;
		}
		if (param === "dept") {
			return s.dept;
		}

		throw new InsightError("no valid param");
	}

	public getParamAll(param: String, s: Section): number | string {
		try {
			return this.getParamString(param, s);
		} catch {
			return this.getParamNum(param, s);
		}
	}

	public async getQueryId(options: any): Promise<string> {
		// TODO: return dataset id from first element of column
		// check for no column and empty column
		const columns = options.COLUMNS as any;
		if (!columns) {
			throw new InsightError("no columns");
		}
		if (columns.length === 0) {
			throw new InsightError("column is empty");
		}
		const id = columns[0].split("_")[0];
		return id;
	}

	public isValidId(id: string): boolean {
		const trimmedId = id.trim();
		return trimmedId.length > 0 && !trimmedId.includes("_") && !trimmedId.includes(" ");
	}

	public getValueType(value: string): string {
		if (value.startsWith("*") && value.endsWith("*")) {
			const newString = value.slice(1, -1);
			if (newString.includes("*")) {
				throw new InsightError("Invalid wildcards filter: * found in the middle");
			}
			return "startend";
		} else if (value.startsWith("*")) {
			const newString = value.slice(1);
			if (newString.includes("*")) {
				throw new InsightError("Invalid wildcards filter: * found in the middle");
			}
			return "start";
		} else if (value.endsWith("*")) {
			const newString = value.slice(0, -1);
			if (newString.includes("*")) {
				throw new InsightError("Invalid wildcards filter: * found in the middle");
			}
			return "end";
		} else if (value.includes("*")) {
			throw new InsightError("Invalid wildcards filter: * found in the middle");
		} else {
			return "normal";
		}
	}

	public async handleGreaterThan(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		const [key, value]: [string, unknown] = Object.entries(where.GT)[0];
		const param = key.split("_")[1];
		const dataset = key.split("_")[0];
		if (dataset !== queryId) {
			throw new InsightError("");
		}
		if (typeof value !== "number") {
			throw new InsightError(`Invalid value type for ${key}. Expected a number but got ${typeof value}`);
		}

		if (isNaN(value)) {
			throw new InsightError(`Invalid value for ${key}. NaN is not allowed.`);
		}

		return sections.filter((s) => {
			return this.getParamNum(param, s) > value;
		});
	}

	public async handleLessThan(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		const [key, value]: [string, unknown] = Object.entries(where.LT)[0];
		const param = key.split("_")[1];
		const dataset = key.split("_")[0];
		if (dataset !== queryId) {
			throw new InsightError("");
		}
		// console.log(param);
		if (typeof value !== "number") {
			throw new InsightError(`Invalid value type for ${key}. Expected a number but got ${typeof value}`);
		}

		if (isNaN(value)) {
			throw new InsightError(`Invalid value for ${key}. NaN is not allowed.`);
		}

		return sections.filter((s) => {
			return this.getParamNum(param, s) < value;
		});
	}

	public async handleEqual(where: any, sections: Section[], queryId: string): Promise<Section[]> {
		const [key, value]: [string, unknown] = Object.entries(where.EQ)[0];
		const param = key.split("_")[1];
		const dataset = key.split("_")[0];
		if (dataset !== queryId) {
			throw new InsightError("");
		}
		// console.log(param);
		if (typeof value !== "number") {
			throw new InsightError(`Invalid value type for ${key}. Expected a number but got ${typeof value}`);
		}

		if (isNaN(value)) {
			throw new InsightError(`Invalid value for ${key}. NaN is not allowed.`);
		}
		return sections.filter((s) => {
			return this.getParamNum(param, s) === value;
		});
	}
}
